import{_ as e,o as r,c as o,ag as t}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),i={name:"faq.md"};function l(h,a,n,s,d,c){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="一般问题" tabindex="-1">一般问题 <a class="header-anchor" href="#一般问题" aria-label="Permalink to &quot;一般问题&quot;">​</a></h2><h3 id="如何开始使用-storyforge" tabindex="-1">如何开始使用 StoryForge？ <a class="header-anchor" href="#如何开始使用-storyforge" aria-label="Permalink to &quot;如何开始使用 StoryForge？&quot;">​</a></h3><p>请参考<a href="./getting-started">快速开始</a>指南，了解如何安装和启动项目。</p><h3 id="storyforge-支持哪些视频格式" tabindex="-1">StoryForge 支持哪些视频格式？ <a class="header-anchor" href="#storyforge-支持哪些视频格式" aria-label="Permalink to &quot;StoryForge 支持哪些视频格式？&quot;">​</a></h3><p>StoryForge 支持 MP4、MOV、AVI、MKV 等常见视频格式。</p><h3 id="storyforge-是免费的吗" tabindex="-1">StoryForge 是免费的吗？ <a class="header-anchor" href="#storyforge-是免费的吗" aria-label="Permalink to &quot;StoryForge 是免费的吗？&quot;">​</a></h3><p>StoryForge 本身是开源免费的，但使用 AI 服务（如 OpenAI、Azure 等）可能需要付费。</p><h2 id="ai-相关问题" tabindex="-1">AI 相关问题 <a class="header-anchor" href="#ai-相关问题" aria-label="Permalink to &quot;AI 相关问题&quot;">​</a></h2><h3 id="是否需要-ai-api-密钥" tabindex="-1">是否需要 AI API 密钥？ <a class="header-anchor" href="#是否需要-ai-api-密钥" aria-label="Permalink to &quot;是否需要 AI API 密钥？&quot;">​</a></h3><p>是的，需要配置 AI 模型服务才能使用 AI 分析和生成功能。请参考 <a href="./ai-config">AI 模型配置</a> 指南。</p><h3 id="如何获取-ai-api-密钥" tabindex="-1">如何获取 AI API 密钥？ <a class="header-anchor" href="#如何获取-ai-api-密钥" aria-label="Permalink to &quot;如何获取 AI API 密钥？&quot;">​</a></h3><p>你可以在以下平台申请 API 密钥：</p><ul><li><a href="https://platform.openai.com/api-keys" target="_blank" rel="noreferrer">OpenAI Platform</a></li><li><a href="https://portal.azure.com" target="_blank" rel="noreferrer">Azure Portal</a></li><li><a href="https://open.bigmodel.cn/" target="_blank" rel="noreferrer">智谱 AI 开放平台</a></li></ul><h3 id="支持哪些-ai-模型" tabindex="-1">支持哪些 AI 模型？ <a class="header-anchor" href="#支持哪些-ai-模型" aria-label="Permalink to &quot;支持哪些 AI 模型？&quot;">​</a></h3><p>StoryForge 支持多种模型提供商：</p><ul><li>OpenAI GPT 系列</li><li>Azure OpenAI</li><li>智谱 GLM 系列</li><li>百度文心一言</li><li>阿里通义千问</li></ul><h2 id="技术问题" tabindex="-1">技术问题 <a class="header-anchor" href="#技术问题" aria-label="Permalink to &quot;技术问题&quot;">​</a></h2><h3 id="启动开发服务器失败怎么办" tabindex="-1">启动开发服务器失败怎么办？ <a class="header-anchor" href="#启动开发服务器失败怎么办" aria-label="Permalink to &quot;启动开发服务器失败怎么办？&quot;">​</a></h3><ol><li>确保 Node.js 版本 ≥ 18.0.0</li><li>清除缓存：<code>npm cache clean --force</code></li><li>删除 node_modules 后重新安装：<code>rm -rf node_modules &amp;&amp; npm install</code></li></ol><h3 id="视频处理需要-gpu-吗" tabindex="-1">视频处理需要 GPU 吗？ <a class="header-anchor" href="#视频处理需要-gpu-吗" aria-label="Permalink to &quot;视频处理需要 GPU 吗？&quot;">​</a></h3><p>基础功能不需要 GPU。GPU 主要用于加速 AI 模型推理，推荐用于生产环境。</p><h3 id="如何报告问题或建议" tabindex="-1">如何报告问题或建议？ <a class="header-anchor" href="#如何报告问题或建议" aria-label="Permalink to &quot;如何报告问题或建议？&quot;">​</a></h3><p>请在 <a href="https://github.com/Agions/StoryForge/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 中提交，我们会尽快处理。</p>',24)])])}const f=e(i,[["render",l]]);export{u as __pageData,f as default};
